import React, { useEffect, useRef, useState } from "react";
import { useLocation } from "react-router-dom";

interface TenorGifProps {
  postId: string;
}

export default function TenorGif({ postId }: TenorGifProps) {
  const ref = useRef<HTMLDivElement>(null);
  const location = useLocation();
  const [ready, setReady] = useState(false);

  useEffect(() => {
    setReady(false);

    const timer = setTimeout(() => {
      if ((window as any).Tenor) {
        // Manually trigger Tenor library to scan for the new embed div
        (window as any).Tenor.load();

        // Polling check to see when the iframe is actually injected to hide loader
        let checkCount = 0;
        const checkInterval = setInterval(() => {
          if (ref.current?.querySelector("iframe")) {
            setReady(true);
            clearInterval(checkInterval);
          }
          if (++checkCount > 15) clearInterval(checkInterval);
        }, 200);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [postId, location.pathname, location.hash]);

  return (
    <div className="gif-wrapper">
      {!ready && (
        <div className="gif-loader">
          <div className="flex flex-col items-center gap-2">
            <span className="text-xl">💗</span>
            <span className="text-[10px] uppercase font-bold tracking-widest">Loading love...</span>
          </div>
        </div>
      )}

      <div
        ref={ref}
        key={`${postId}-${location.pathname}-${location.hash}`}
        className="tenor-gif-embed"
        data-postid={postId}
        data-share-method="host"
        data-aspect-ratio="1"
        data-width="100%"
      >
        <a href={`https://tenor.com/view/${postId}`}>GIF</a>
      </div>
    </div>
  );
}

import React, { useEffect, useRef, useState } from "react";
import { useLocation } from "react-router-dom";

interface TenorGifProps {
  postId: string;
}

export default function TenorGif({ postId }: TenorGifProps) {
  const ref = useRef<HTMLDivElement>(null);
  const location = useLocation();
  const [ready, setReady] = useState(false);

  useEffect(() => {
    let isMounted = true;

    const initializeTenor = () => {
      if (!isMounted) return;

      // 1. Ensure the Tenor embed script is present in the document
      const SCRIPT_ID = 'tenor-embed-script-managed';
      let script = document.getElementById(SCRIPT_ID) as HTMLScriptElement;

      if (!script) {
        script = document.createElement('script');
        script.id = SCRIPT_ID;
        script.src = "https://tenor.com/embed.js";
        script.async = true;
        document.body.appendChild(script);
      }

      const attemptLoad = () => {
        if (!isMounted) return;

        // 2. Check for Tenor global object and its load method
        if ((window as any).Tenor && typeof (window as any).Tenor.load === 'function') {
          // Re-scan the DOM for Tenor embed containers
          (window as any).Tenor.load();

          // 3. Poll for the actual iframe insertion within our component's ref
          let checkAttempts = 0;
          const checkInterval = setInterval(() => {
            if (!isMounted) {
              clearInterval(checkInterval);
              return;
            }

            if (ref.current?.querySelector("iframe")) {
              setReady(true);
              clearInterval(checkInterval);
            }

            // Max polling: 8 seconds (40 * 200ms) to account for slow network
            if (++checkAttempts > 40) {
              clearInterval(checkInterval);
            }
          }, 200);
        } else {
          // Global object not found yet (script still loading), wait and retry
          setTimeout(attemptLoad, 250);
        }
      };

      // Defer execution slightly to ensure React has finished rendering the placeholder div
      setTimeout(attemptLoad, 100);
    };

    setReady(false);
    initializeTenor();

    return () => {
      isMounted = false;
    };
  }, [postId, location.pathname, location.hash]);

  return (
    <div className="gif-wrapper">
      {!ready && (
        <div className="gif-loader">
          <div className="flex flex-col items-center gap-2">
            <span className="text-xl">💗</span>
            <span className="text-[10px] uppercase font-bold tracking-widest">Loading love...</span>
          </div>
        </div>
      )}

      <div
        ref={ref}
        key={`tenor-embed-${postId}-${location.pathname}-${location.hash}`}
        className="tenor-gif-embed"
        data-postid={postId}
        data-share-method="host"
        data-aspect-ratio="1"
        data-width="100%"
      >
        <a href={`https://tenor.com/view/${postId}`}>GIF</a>
      </div>
    </div>
  );
}

import React, { useEffect, useRef, useState } from "react";
import { useLocation } from "react-router-dom";

interface TenorGifProps {
  postId: string;
}

export default function TenorGif({ postId }: TenorGifProps) {
  const ref = useRef<HTMLDivElement>(null);
  const location = useLocation();
  const [ready, setReady] = useState(false);

  useEffect(() => {
    let isMounted = true;
    let checkInterval: any;

    const loadTenor = () => {
      if (!isMounted) return;

      if ((window as any).Tenor && typeof (window as any).Tenor.load === 'function') {
        // Re-scan the DOM for the newly rendered embed div
        (window as any).Tenor.load();

        // Check for iframe presence to hide the loader
        let attempts = 0;
        checkInterval = setInterval(() => {
          if (!isMounted) {
            clearInterval(checkInterval);
            return;
          }
          if (ref.current?.querySelector("iframe")) {
            setReady(true);
            clearInterval(checkInterval);
          }
          if (++attempts > 30) {
            clearInterval(checkInterval);
          }
        }, 300);
      } else {
        // If script hasn't finished loading yet, retry in 500ms
        setTimeout(loadTenor, 500);
      }
    };

    setReady(false);
    loadTenor();

    return () => {
      isMounted = false;
      if (checkInterval) clearInterval(checkInterval);
    };
  }, [postId, location.pathname, location.hash]);

  return (
    <div className="gif-wrapper">
      {!ready && (
        <div className="gif-loader">
          <div className="flex flex-col items-center gap-2">
            <span className="text-xl">💗</span>
            <span className="text-[10px] uppercase font-bold tracking-widest">Loading love...</span>
          </div>
        </div>
      )}

      <div
        ref={ref}
        key={`tenor-v2-${postId}-${location.pathname}`}
        className="tenor-gif-embed"
        data-postid={postId}
        data-share-method="host"
        data-aspect-ratio="1"
        data-width="100%"
      >
        <a href={`https://tenor.com/view/${postId}`}>GIF</a>
      </div>
    </div>
  );
}
